import json, os

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for proj in data.get('projects', []):
        name = os.path.basename(proj['path'])
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            key = f'{name} ({tfm})'
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(key, {})[pkg['id']] = pkg['resolvedVersion']
    return result

b = extract_packages(baseline)
a = extract_packages(after)

all_keys = sorted(set(list(b.keys()) + list(a.keys())))
changes = []
unchanged = []

for key in all_keys:
    bp = b.get(key, {})
    ap = a.get(key, {})
    all_pkgs = sorted(set(list(bp.keys()) + list(ap.keys())))
    for pkg in all_pkgs:
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            if bv is None:
                status = 'Added'
            elif av is None:
                status = 'Removed'
            else:
                status = 'Aligned to highest'
            changes.append((key, pkg, bv or 'N/A', av or 'N/A', status))
        else:
            unchanged.append((key, pkg, av))

if changes:
    print('=== CHANGES ===')
    print(f'{\"Project\":<25} {\"Package\":<45} {\"Before\":<12} {\"After\":<12} Status')
    print('-' * 110)
    for c in changes:
        print(f'{c[0]:<25} {c[1]:<45} {c[2]:<12} {c[3]:<12} {c[4]}')
else:
    print('No version changes — fully version-neutral.')

print()
print('=== UNCHANGED ===')
print(f'{\"Project\":<25} {\"Package\":<45} {\"Version\":<12}')
print('-' * 85)
for u in unchanged:
    print(f'{u[0]:<25} {u[1]:<45} {u[2]:<12}')
"

